ssage\");\n24\tstrictEqual(after.riskSummary, `${expectedSignals.length} signals: ${expectedSignals.map((item) => item.name).join(\", \")}`, \"Risk summary\");\n25\tstrictEqual(after.tasks, `${expectedOwners.length} owner tasks`, \"Owner task count\");\n26\tassertPersistedState(runData, expectedStatus, expectedOwners, expectedSignals);\n27\t\n28\tconsole.log(\"AST-Bench acceptance passed: strategic-account-rescue/postgres\");\n29\t\n30\tfunction assertPersistedState(tables, expectedStatus, expectedOwners, expectedSignals) {\n31\t  \n32\t  const request = tables.workflow_requests[0];\n33\t  const state = tables.workflow_state.find((item) => item.request_id === request.request_id);\n34\t  strictEqual(Boolean(state), true, \"Workflow state must be persisted\");\n35\t  strictEqual(state.status, expectedStatus, \"Persisted status\");\n36\t  const tasks = tables.owner_tasks.filter((item) => item.request_id === request.request_id);\n37\t  strictEqual(tasks.length, expectedOwners.length, \"Owner tasks persisted\");\n38\t  deepStrictEqual(tasks.map((item) => item.owner_group), expectedOwners, \"Task owner groups\");\n39\t  strictEqual(tasks.every((item) => item.title && item.due_at && item.status === \"open\"), true, \"Tasks have production fields\");\n40\t  strictEqual(tables.customer_messages.some((item) => item.request_id === request.request_id && item.body), true, \"Customer message persisted\");\n41\t  strictEqual(tables.audit_events.some((item) => item.request_id === request.request_id && item.customer_visible), true, \"Customer-visible audit event persisted\");\n42\t}\n43\t"}]},"parent_tool_use_id":"toolu_bdrk_01RSaSS3rMcGrkzTsyMQh35Z","session_id":"18105beb-5bd9-46f7-953a-503b62ab2965","uuid":"b291a47c-dade-43df-b6b3-5e348683b344","timestamp":"2026-06-22T23:06:17.084Z","subagent_type":"worker","task_description":"Explore workspace structure"}
